# EVOLVE-BLOCK-START
import numpy as np
from scipy.optimize import minimize

def construct_packing():
    n = 26
    ii, jj = np.triu_indices(n, 1)

    def fv(x):
        return -np.sum(np.exp(x[2*n:]))
    def cwv(x):
        c, r = x[:2*n].reshape(n,2), np.exp(x[2*n:])
        return np.r_[c[:,0]-r, 1-c[:,0]-r, c[:,1]-r, 1-c[:,1]-r]
    def ccv(x):
        c, r = x[:2*n].reshape(n,2), np.exp(x[2*n:])
        return np.sqrt(((c[ii]-c[jj])**2).sum(1)) - r[ii] - r[jj]
    cons = [{'type':'ineq','fun':cwv},{'type':'ineq','fun':ccv}]

    def ok(c, r, tol=1e-6):
        if np.any(c[:,0]-r<-tol) or np.any(c[:,0]+r>1+tol): return False
        if np.any(c[:,1]-r<-tol) or np.any(c[:,1]+r>1+tol): return False
        return np.all(np.sqrt(((c[ii]-c[jj])**2).sum(1)) >= r[ii]+r[jj]-tol)

    best_s, best_c, best_r = 0, None, None
    def upd(c, r):
        nonlocal best_s, best_c, best_r
        if ok(c, r) and np.sum(r) > best_s:
            best_s, best_c, best_r = np.sum(r), c.copy(), r.copy()

    def make_hex(r, rows, offs):
        dx, dy = 2*r, r*3**0.5
        pts = []
        for i, cnt in enumerate(rows):
            y = r + i*dy
            for j in range(cnt):
                pts.append([r + offs[i]*r + j*dx, y])
        c = np.array(pts[:n])
        sc = min(1/(c[:,0].max()+r), 1/(c[:,1].max()+r))
        return c*sc, np.full(n, r*sc)

    layouts = [([6,5,6,5,4],[0,1,0,1,0]),([5,6,5,6,4],[1,0,1,0,0]),
               ([6,5,6,5,4],[0,1,0,1,1]),([5,5,6,5,5],[0,1,0,1,0]),
               ([5,6,5,5,5],[1,0,1,0,1]),([6,5,5,5,5],[0,1,0,1,0]),
               ([5,5,5,6,5],[0,1,0,1,0]),([6,5,6,4,5],[0,1,0,1,0]),
               ([4,5,4,5,4,4],[0,1,0,1,0,1]),([5,4,5,4,4,4],[0,1,0,1,0,1]),
               ([4,5,5,4,4,4],[1,0,1,0,1,0]),([5,5,5,5,6],[0,1,0,1,0])]
    cfgs = []
    for r0 in [0.093,0.096,0.0985,0.0995,0.1005,0.1010,0.10127,0.1015,0.1020,0.1025,0.1035]:
        for rows, offs in layouts:
            if sum(rows) >= n:
                cfgs.append(make_hex(r0, rows, offs))

    for c0, r0 in cfgs:
        x0 = np.r_[c0.ravel(), np.log(r0[0])]
        def fu(x): return -n*np.exp(x[-1])
        def cwu(x):
            c, r = x[:2*n].reshape(n,2), np.exp(x[-1])
            return np.r_[c[:,0]-r,1-c[:,0]-r,c[:,1]-r,1-c[:,1]-r]
        def ccu(x):
            c, r = x[:2*n].reshape(n,2), np.exp(x[-1])
            return np.sqrt(((c[ii]-c[jj])**2).sum(1)) - 2*r
        try:
            res = minimize(fu, x0, method='SLSQP',
                constraints=[{'type':'ineq','fun':cwu},{'type':'ineq','fun':ccu}],
                options={'maxiter':5000,'ftol':1e-15})
            cu = res.x[:2*n].reshape(n,2); ru = np.full(n, np.exp(res.x[-1]))
            if ok(cu, ru):
                x1 = np.r_[cu.ravel(), np.log(ru)]
                for ft in [1e-10, 1e-14]:
                    res2 = minimize(fv, x1, method='SLSQP', constraints=cons,
                        options={'maxiter':15000,'ftol':ft})
                    c2, r2 = res2.x[:2*n].reshape(n,2), np.exp(res2.x[2*n:])
                    upd(c2, r2); x1 = res2.x
        except: pass

    for s in range(30):
        np.random.seed(s+5)
        xp = np.r_[best_c.ravel(), np.log(best_r)]
        sc = 0.002*(1+s%6)
        xp[:2*n] += np.random.randn(2*n)*sc
        xp[2*n:] += np.random.randn(n)*sc*0.5
        try:
            res = minimize(fv, xp, method='SLSQP', constraints=cons,
                options={'maxiter':15000,'ftol':1e-15})
            c3, r3 = res.x[:2*n].reshape(n,2), np.exp(res.x[2*n:])
            upd(c3, r3)
        except: pass

    return best_c, best_r, float(best_s)
# EVOLVE-BLOCK-END

def run_packing():
    centers, radii, sum_radii = construct_packing()
    return centers, radii, sum_radii

if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii}")
